   471→    // Initialize coefficients
   472→    let mut beta = Array1::zeros(n_vars);
   473→    let mut residuals = y_centered.clone();
   474→
   475→    // Pre-compute X'X diagonal for efficiency
   476→    let xtx_diag: Array1<f64> = x_std
   477→        .axis_iter(ndarray::Axis(1))
   478→        .map(|col| col.dot(&col))
   479→        .collect();
   480→
   481→    let mut prev_beta = beta.clone();
   482→
   483→    for iteration in 0..config.max_iter {
   484→        // Coordinate descent updates
   485→        for j in 0..n_vars {
   486→            if xtx_diag[j] == 0.0 {
   487→                continue; // Skip zero-variance features
   488→            }
   489→
   490→            // Calculate partial residual
   491→            let col_j = x_std.column(j);
   492→            let partial_residual = &residuals + beta[j] * &col_j;
   493→
   494→            // Calculate coordinate update
   495→            let xty = col_j.dot(&partial_residual);
   496→            let new_beta_j = soft_threshold(xty, config.lambda * config.alpha)
   497→                / (xtx_diag[j] + config.lambda * (1.0 - config.alpha));
   498→
   499→            // Update coefficient and residuals
   500→            let _delta = new_beta_j - beta[j];
   501→            beta[j] = new_beta_j;
   502→            residuals = &partial_residual - new_beta_j * &col_j;
   503→        }
   504→
   505→        // Check convergence
   506→        let max_change = (&beta - &prev_beta)
   507→            .mapv(f64::abs)
   508→            .fold(0.0f64, |acc, &val| acc.max(val));
   509→        if max_change < config.tolerance {
   510→            // Transform coefficients back to original scale
   511→            let final_beta = if config.standardize {
   512→                transform_coefficients_back(&beta, &x_means, &x_scales, y_mean)
   513→            } else {
   514→                beta
   515→            };
   516→
   517→            let linear_predictor = x.dot(&final_beta);
   518→
   519→            return Ok(OptimResult {
   520→                params: final_beta,
   521→                iterations: iteration,
   522→                converged: true,
   523→                deviance: residuals.mapv(|r| r * r).sum(),
   524→                weights: Array1::ones(n_obs), // Unweighted for now
   525→                linear_predictor,
   526→            });
   527→        }
   528→
   529→        prev_beta.assign(&beta);
   530→    }
   531→
   532→    // Did not converge
   533→    let final_beta = if config.standardize {
   534→        transform_coefficients_back(&beta, &x_means, &x_scales, y_mean)
   535→    } else {
   536→        beta
   537→    };
   538→
   539→    let linear_predictor = x.dot(&final_beta);
   540→
   541→    Ok(OptimResult {
   542→        params: final_beta,
   543→        iterations: config.max_iter,
   544→        converged: false,
   545→        deviance: residuals.mapv(|r| r * r).sum(),
   546→        weights: Array1::ones(n_obs),
   547→        linear_predictor,
   548→    })
   549→}
